from typing import List

class Solution:
    def isValid(self, board: List[List[int]]) -> bool:
        for k in range(len(board)):
            for m in range(len(board)):
                for i in range(len(board)):
                    for j in range(len(board)):
                        if i == k:
                            continue
                        if m == j:
                            continue
                        if k == m and (i - k == j - m or i - k == 3 - (j - m)):
                            continue
                        if board[k][m] == board[i][j]:
                            return False
        return True

    def solve(self, board: List[List[int]]) -> bool:
        # Find the index of the empty cell
        for k in range(len(board)):
            for m in range(len(board)):
                if board[k][m] == 0:
                    # Fill in the cell with 1 to 9 and check if the puzzle is valid
                    for n in range(1, 10):
                        board[k][m] = n
                        if self.isValid(board):
                            return True
                    # If the puzzle is not valid, backtrack and return False
                    return False
        # If no empty cells are found, return True
        return True

