#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    bool isValid(vector<vector<int>>& board) {
        int rows = board.size(); 
        int cols = board[0].size();
        bool visited[rows][cols];
        memset(visited, false, sizeof(visited));

        for (int k = 0; k < rows; ++k) {
            for (int m = 0; m < cols; ++m) {
                if (board[k][m] == 0) {
                    for (int n = 1; n <= 9; ++n) {
                        board[k][m] = n;
                        if (isValidBacktracking(board, k, m, 0))
                            return true;
                        board[k][m] = 0;
                    }
                    return false;
                }
            }
        }

        return true;
    }

    bool isValidBacktracking(vector<vector<int>>& board, int k, int m, int step) {
        int rows = board.size();
        int cols = board[0].size();

        if (step >= rows * cols)
            return true;

        int x = step / cols;
        int y = step % cols;

        if (x == k) 
            continue;
        if (m == y) 
            continue;
        if (k == m && (x - k == y - m || x - k == 3 - (y - m))) 
            continue;

        if (board[x][y] == board[k][m]) 
            return false;

        board[x][y] = board[k][m];
        if (isValidBacktracking(board, k, m, step + 1))
            return true;
        board[x][y] = 0;

        return false;
    }

    bool solve(vector<vector<int>>& board) {
        int rows = board.size(); 
        int cols = board[0].size();

        int step = 0;

        for (int i = 0; i < rows; ++i) {
            for (int j = 0; j < cols; ++j) {
                if (board[i][j] == 0)
                    step += 1;
            }
        }

        return isValid(board);
    }
};

int main() {
    Solution solution;
    vector<vector<int>> board = {{5, 3, 0, 0, 7, 0, 0, 0, 0}, {6, 0, 0, 1, 9, 5, 0, 0, 0}, {8, 0, 0, 0, 6, 0, 0, 0, 3}, {4, 0, 8, 0, 3, 0, 0, 0, 1}, {7, 0, 0, 0, 2, 0, 0, 0, 6}, {0, 6, 0, 0, 0, 0, 2, 8, 0}, {0, 0, 0, 4, 1, 9, 0, 0, 5}, {0, 0, 0, 0, 8, 0, 0, 7, 9}, {0, 0, 0, 0, 0, 0, 0, 0, 0}};

    cout << (solution.solve(board) ? 'true' : 'false') << std::endl;

    return 0;
}
